mapper.select:
WITH VALT_SCHD AS ( SELECT MAX(VALT_TRN) AS VALT_TRN FROM RBA_RSK_VALT_SCHD
WHERE VALT_TRN > 0
AND VALT_G = '1'
AND VALT_SDT <= TO_CHAR(SYSDATE,'YYYYMMDD')
) SELECT CC.IRSK_T_CNT AS A11 ,CC.IRSK_VALT_CNT AS A12 ,DECODE(CC.IRSK_T_CNT, 0, 0, ROUND(CC.IRSK_VALT_CNT/CC.IRSK_T_CNT * 100, 2)) AS A13
,CC.IRSK_TONGJE4_CNT AS A14 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_TONGJE4_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A15 ,CC.IRSK_TONGJE3_CNT AS A16 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_TONGJE3_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A17 ,CC.IRSK_TONGJE2_CNT AS A18 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_TONGJE2_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A19 ,CC.IRSK_TONGJE1_CNT AS A20 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_TONGJE1_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A21
,CC.IRSK_REMDR4_CNT AS A22 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_REMDR4_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A23 ,CC.IRSK_REMDR3_CNT AS A24 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_REMDR3_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A25 ,CC.IRSK_REMDR2_CNT AS A26 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_REMDR2_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A27 ,CC.IRSK_REMDR1_CNT AS A28 ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.IRSK_REMDR1_CNT/CC.IRSK_VALT_CNT * 100, 2)) AS A29 FROM ( SELECT SUM(IRSK_T_CNT) AS IRSK_T_CNT ,SUM(IRSK_VALT_CNT) AS IRSK_VALT_CNT ,SUM(IRSK_TONGJE4_CNT) AS IRSK_TONGJE4_CNT ,SUM(IRSK_TONGJE3_CNT) AS IRSK_TONGJE3_CNT ,SUM(IRSK_TONGJE2_CNT) AS IRSK_TONGJE2_CNT ,SUM(IRSK_TONGJE1_CNT) AS IRSK_TONGJE1_CNT ,SUM(IRSK_REMDR4_CNT) AS IRSK_REMDR4_CNT ,SUM(IRSK_REMDR3_CNT) AS IRSK_REMDR3_CNT ,SUM(IRSK_REMDR2_CNT) AS IRSK_REMDR2_CNT ,SUM(IRSK_REMDR1_CNT) AS IRSK_REMDR1_CNT FROM ( SELECT COUNT(RSK_NO) AS IRSK_T_CNT ,0 AS IRSK_VALT_CNT ,0 AS IRSK_TONGJE4_CNT ,0 AS IRSK_TONGJE3_CNT ,0 AS IRSK_TONGJE2_CNT ,0 AS IRSK_TONGJE1_CNT ,0 AS IRSK_REMDR4_CNT ,0 AS IRSK_REMDR3_CNT ,0 AS IRSK_REMDR2_CNT ,0 AS IRSK_REMDR1_CNT FROM RBA_RSK_M X WHERE X.RSK_B_C = 'I' AND X.USYN = 1 AND X.GYLJ_DT IS NOT NULL AND X.MNG_BRNO ! = '9999'
AND X.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
UNION ALL SELECT 0 as IRSK_T_CNT ,COUNT(B.RSK_NO) AS IRSK_VALT_CNT ,NVL(SUM(DECODE(B.MOFC_TONGJE_GD, 4, 1, 0)),0) AS IRSK_TONGJE4_CNT ,NVL(SUM(DECODE(B.MOFC_TONGJE_GD, 3, 1, 0)),0) AS IRSK_TONGJE3_CNT ,NVL(SUM(DECODE(B.MOFC_TONGJE_GD, 2, 1, 0)),0) AS IRSK_TONGJE2_CNT ,NVL(SUM(DECODE(B.MOFC_TONGJE_GD, 1, 1, 0)),0) AS IRSK_TONGJE1_CNT ,NVL(SUM(DECODE(B.REMDR_RSK_GD, 4, 1, 0)),0) AS IRSK_REMDR4_CNT ,NVL(SUM(DECODE(B.REMDR_RSK_GD, 3, 1, 0)),0) AS IRSK_REMDR3_CNT ,NVL(SUM(DECODE(B.REMDR_RSK_GD, 2, 1, 0)),0) AS IRSK_REMDR2_CNT ,NVL(SUM(DECODE(B.REMDR_RSK_GD, 1, 1, 0)),0) AS IRSK_REMDR1_CNT FROM RBA_RSK_M A , RBA_IRSK_VALT_I B LEFT OUTER JOIN RBA_TJ_IMPRV_V_I C ON B.RSK_NO = C.RSK_NO AND B.VALT_TRN = C.VALT_TRN AND B.VALT_SER = C.VALT_SER , VALT_SCHD Z WHERE A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER /* 현재회차 평가건 또는 이전회차 개신진행중 */
AND (A.LST_VALT_TRN = Z.VALT_TRN OR (B.IMPRV_K_C > '0' AND NVL(C.IMPRV_PROC_APRV_S_C, 0) < 7))
AND RSK_B_C = 'I' AND A.USYN = '1' AND A.GYLJ_DT IS NOT NULL AND B.VALT_JINHG_S_C IN ('2','9')
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
) BB ) CC

WITH VALT_SCHD AS ( SELECT MAX(VALT_TRN) AS VALT_TRN FROM RBA_RSK_VALT_SCHD
WHERE VALT_TRN > 0
AND VALT_G = '1'
AND VALT_SDT <= TO_CHAR(SYSDATE,'YYYYMMDD')
) SELECT CC.TRSK_T_CTN AS A31 ,CC.TONGJE_CNT AS A32 ,CC.TRSK_VALT_CNT AS A33 ,DECODE(CC.TRSK_T_CTN, 0, 0, ROUND(CC.TRSK_VALT_CNT/CC.TRSK_T_CTN * 100, 2)) AS A34 ,CC.TRSK4_CNT AS A35 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK4_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A36 ,CC.TRSK3_CNT AS A37 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK3_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A38 ,CC.TRSK2_CNT AS A39 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK2_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A40 ,CC.TRSK1_CNT AS A41 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK1_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A42 ,CC.TRSK_TONGJE4_CNT AS A43 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_TONGJE4_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A44 ,CC.TRSK_TONGJE3_CNT AS A45 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_TONGJE3_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A46 ,CC.TRSK_TONGJE2_CNT AS A47 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_TONGJE2_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A48 ,CC.TRSK_TONGJE1_CNT AS A49 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_TONGJE1_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A50 ,CC.TRSK_REMDR4_CNT AS A51 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_REMDR4_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A52 ,CC.TRSK_REMDR3_CNT AS A53 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_REMDR3_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A54 ,CC.TRSK_REMDR2_CNT AS A55 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_REMDR2_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A56 ,CC.TRSK_REMDR1_CNT AS A57 ,DECODE(CC.TRSK_VALT_CNT, 0, 0, ROUND(CC.TRSK_REMDR1_CNT/CC.TRSK_VALT_CNT * 100, 2)) AS A58 FROM ( SELECT SUM(TRSK_T_CTN) AS TRSK_T_CTN ,SUM(TONGJE_CNT) AS TONGJE_CNT ,SUM(TRSK_VALT_CNT) AS TRSK_VALT_CNT ,SUM(TRSK4_CNT) AS TRSK4_CNT ,SUM(TRSK3_CNT) AS TRSK3_CNT ,SUM(TRSK2_CNT) AS TRSK2_CNT ,SUM(TRSK1_CNT) AS TRSK1_CNT ,SUM(TRSK_TONGJE4_CNT) AS TRSK_TONGJE4_CNT ,SUM(TRSK_TONGJE3_CNT) AS TRSK_TONGJE3_CNT ,SUM(TRSK_TONGJE2_CNT) AS TRSK_TONGJE2_CNT ,SUM(TRSK_TONGJE1_CNT) AS TRSK_TONGJE1_CNT ,SUM(TRSK_REMDR4_CNT) AS TRSK_REMDR4_CNT ,SUM(TRSK_REMDR3_CNT) AS TRSK_REMDR3_CNT ,SUM(TRSK_REMDR2_CNT) AS TRSK_REMDR2_CNT ,SUM(TRSK_REMDR1_CNT) AS TRSK_REMDR1_CNT FROM ( SELECT COUNT(RSK_NO) AS TRSK_T_CTN ,MAX((SELECT COUNT(*) FROM RBA_RSK_TONGJE_MP WHERE RSK_NO = X.RSK_NO)) AS TONGJE_CNT ,0 AS TRSK_VALT_CNT ,0 AS TRSK4_CNT ,0 AS TRSK3_CNT ,0 AS TRSK2_CNT ,0 AS TRSK1_CNT ,0 AS TRSK_TONGJE4_CNT ,0 AS TRSK_TONGJE3_CNT ,0 AS TRSK_TONGJE2_CNT ,0 AS TRSK_TONGJE1_CNT ,0 AS TRSK_REMDR4_CNT ,0 AS TRSK_REMDR3_CNT ,0 AS TRSK_REMDR2_CNT ,0 AS TRSK_REMDR1_CNT FROM RBA_RSK_M X WHERE X.RSK_B_C = 'T' AND X.USYN = 1 AND X.GYLJ_DT IS NOT NULL
AND X.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
UNION ALL
SELECT 0 AS TRSK_T_CTN ,0 AS TONGJE_CNT ,COUNT(B.RSK_NO) AS TRSK_VALT_CNT
,NVL(SUM(DECODE(B.KRI_UNTY_RSK_GD, 4, 1, 0)),0) AS TRSK4_CNT ,NVL(SUM(DECODE(B.KRI_UNTY_RSK_GD, 3, 1, 0)),0) AS TRSK3_CNT ,NVL(SUM(DECODE(B.KRI_UNTY_RSK_GD, 2, 1, 0)),0) AS TRSK2_CNT ,NVL(SUM(DECODE(B.KRI_UNTY_RSK_GD, 1, 1, 0)),0) AS TRSK1_CNT
,NVL(SUM(DECODE(B.LST_TONGJE_VALT_GD, 4, 1, 0)),0) AS TRSK_TONGJE4_CNT ,NVL(SUM(DECODE(B.LST_TONGJE_VALT_GD, 3, 1, 0)),0) AS TRSK_TONGJE3_CNT ,NVL(SUM(DECODE(B.LST_TONGJE_VALT_GD, 2, 1, 0)),0) AS TRSK_TONGJE2_CNT ,NVL(SUM(DECODE(B.LST_TONGJE_VALT_GD, 1, 1, 0)),0) AS TRSK_TONGJE1_CNT
,NVL(SUM(DECODE(B.REMDR_RSK_GD, 4, 1, 0)),0) AS TRSK_REMDR4_CNT ,NVL(SUM(DECODE(B.REMDR_RSK_GD, 3, 1, 0)),0) AS TRSK_REMDR3_CNT ,NVL(SUM(DECODE(B.REMDR_RSK_GD, 2, 1, 0)),0) AS TRSK_REMDR2_CNT ,NVL(SUM(DECODE(B.REMDR_RSK_GD, 1, 1, 0)),0) AS TRSK_REMDR1_CNT FROM RBA_RSK_M A , RBA_TRSK_VALT_I B , VALT_SCHD Z WHERE A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER /* 통합위험 현재회차에서만 구함. */ AND A.LST_VALT_TRN = Z.VALT_TRN AND A.RSK_B_C = 'T' AND A.USYN = '1' AND B.MNG_BRNO = '9999' -- 공통 AND A.GYLJ_DT IS NOT NULL AND B.VALT_JINHG_S_C IN ('2','9') -- 완료(재평가가능), 완료(개선사항) 확인
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
) BB ) CC

WITH VALT_SCHD AS ( SELECT MAX(VALT_TRN) AS VALT_TRN FROM RBA_RSK_VALT_SCHD
WHERE VALT_TRN > 0
AND VALT_G = '1'
AND VALT_SDT <= TO_CHAR(SYSDATE,'YYYYMMDD')
) SELECT IRSK_T_CNT AS B01, AVG_IRSK_SCORE AS B02, AVG_IRSK_GD AS B03, AVG_ITONGJE_SCORE AS B04, AVG_ITONGJE_GD AS B05 ,TRSK_T_CNT AS B06, AVG_TRSK_SCORE AS B07, AVG_TRSK_GD AS B08, AVG_TTONGJE_SCORE AS B09, AVG_TTONGJE_GD AS B10 ,RSK_T_CNT AS B11, AVG_RSK_SCORE AS B12, AVG_RSK_GD AS B13, AVG_TONGJE_SCORE AS B14, AVG_TONGJE_GD AS B15 ,REMR_RSK_GD AS B16 ,GET_CODE_NAME('R013',REMR_RSK_GD) AS B17 ,GET_CODE_NAME('R014',REMR_RSK_GD) AS B18 FROM ( SELECT IRSK_T_CNT, AVG_IRSK_SCORE, AVG_IRSK_GD, AVG_ITONGJE_SCORE, AVG_ITONGJE_GD ,TRSK_T_CNT, AVG_TRSK_SCORE, AVG_TRSK_GD, AVG_TTONGJE_SCORE, AVG_TTONGJE_GD ,(IRSK_T_CNT + TRSK_T_CNT) AS RSK_T_CNT ,ROUND((AVG_IRSK_SCORE + AVG_IRSK_SCORE)/2,2) AS AVG_RSK_SCORE ,ROUND((AVG_IRSK_GD + AVG_TRSK_GD)/2,0) AS AVG_RSK_GD ,ROUND((AVG_ITONGJE_SCORE + AVG_TTONGJE_SCORE)/2,2) AS AVG_TONGJE_SCORE ,ROUND((AVG_ITONGJE_GD + AVG_TTONGJE_GD)/2,0) AS AVG_TONGJE_GD ,(SELECT RSK_GD FROM RBA_RSK_GD_M A, RBA_RSK_GD_S B WHERE A.RSK_GD_HMK_C = 3 AND A.RSK_GD_HMK_C = B.RSK_GD_HMK_C AND A.LST_SER = B.RSK_GD_SER AND B.RSK_GD_X_V = ROUND((AVG_ITONGJE_GD + AVG_TTONGJE_GD)/2,0) AND B.RSK_GD_Y_V = ROUND((AVG_IRSK_GD + AVG_TRSK_GD)/2,0) AND ROWNUM = 1 ) REMR_RSK_GD FROM (SELECT CC.IRSK_T_CNT ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.INDV_RSK_VALT_PNT / CC.IRSK_VALT_CNT * 0.8,2) ) AS AVG_IRSK_SCORE ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.INDV_RSK_GD / CC.IRSK_VALT_CNT, 0) ) AS AVG_IRSK_GD ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.MOFC_TONGJE_VALT_PNT / CC.IRSK_VALT_CNT,2) ) AS AVG_ITONGJE_SCORE ,DECODE(CC.IRSK_VALT_CNT, 0, 0, ROUND(CC.MOFC_TONGJE_GD / CC.IRSK_VALT_CNT, 0) ) AS AVG_ITONGJE_GD FROM ( SELECT SUM(IRSK_T_CNT) AS IRSK_T_CNT ,SUM(IRSK_VALT_CNT) AS IRSK_VALT_CNT ,SUM(INDV_RSK_VALT_PNT) AS INDV_RSK_VALT_PNT ,SUM(INDV_RSK_GD) AS INDV_RSK_GD ,SUM(MOFC_TONGJE_VALT_PNT) AS MOFC_TONGJE_VALT_PNT ,SUM(MOFC_TONGJE_GD) AS MOFC_TONGJE_GD FROM (
SELECT COUNT(RSK_NO) AS IRSK_T_CNT ,0 AS IRSK_VALT_CNT ,0 AS INDV_RSK_VALT_PNT ,0 AS INDV_RSK_GD ,0 AS MOFC_TONGJE_VALT_PNT ,0 AS MOFC_TONGJE_GD
FROM RBA_RSK_M X WHERE X.RSK_B_C = 'I' AND X.USYN = 1 AND X.GYLJ_DT IS NOT NULL AND X.MNG_BRNO ! = '9999'
AND X.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND X.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND X.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
GROUP BY X.MNG_BRNO UNION ALL SELECT 0 as IRSK_T_CNT ,COUNT(B.RSK_NO) AS IRSK_VALT_CNT ,NVL(SUM(B.INDV_RSK_VALT_PNT),0) AS INDV_RSK_VALT_PNT ,NVL(SUM(B.INDV_RSK_GD),1) AS INDV_RSK_GD ,NVL(SUM(B.MOFC_TONGJE_VALT_PNT),0) AS MOFC_TONGJE_VALT_PNT ,NVL(SUM(B.MOFC_TONGJE_GD),1) AS MOFC_TONGJE_GD FROM RBA_RSK_M A , RBA_IRSK_VALT_I B LEFT OUTER JOIN RBA_TJ_IMPRV_V_I C ON B.RSK_NO = C.RSK_NO AND B.VALT_TRN = C.VALT_TRN AND B.VALT_SER = C.VALT_SER , VALT_SCHD Z WHERE A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER /* 현재회차 평가건 또는 이전회차 개신진행중 */
AND (A.LST_VALT_TRN = Z.VALT_TRN OR (B.IMPRV_K_C > '0' AND NVL(C.IMPRV_PROC_APRV_S_C, 0) < 7))
AND RSK_B_C = 'I' AND A.USYN = '1' AND A.GYLJ_DT IS NOT NULL
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
AND B.VALT_JINHG_S_C IN ('2','9') ) BB ) CC ) FF, ( SELECT TRSK_T_CNT ,DECODE(TRSK_VALT_CNT, 0, 0, ROUND(KRI_RSK_VALT_PNT / TRSK_VALT_CNT,2)) AS AVG_TRSK_SCORE ,DECODE(TRSK_VALT_CNT, 0, 0, ROUND(KRI_RSK_GD / TRSK_VALT_CNT, 0)) AS AVG_TRSK_GD ,DECODE(TRSK_VALT_CNT, 0, 0, ROUND(TONGJE_VALT_PNT / TRSK_VALT_CNT,2)) AS AVG_TTONGJE_SCORE ,DECODE(TRSK_VALT_CNT, 0, 0, ROUND(TONGJE_GD / TRSK_VALT_CNT, 0)) AS AVG_TTONGJE_GD FROM ( SELECT SUM(TRSK_T_CNT) AS TRSK_T_CNT ,SUM(TRSK_VALT_CNT) AS TRSK_VALT_CNT ,SUM(KRI_RSK_VALT_PNT) AS KRI_RSK_VALT_PNT ,SUM(KRI_RSK_GD) AS KRI_RSK_GD ,SUM(TONGJE_VALT_PNT) AS TONGJE_VALT_PNT ,SUM(TONGJE_GD) AS TONGJE_GD FROM ( SELECT COUNT(RSK_NO) AS TRSK_T_CNT ,0 AS TRSK_VALT_CNT ,0 AS KRI_RSK_VALT_PNT ,0 AS KRI_RSK_GD ,0 AS TONGJE_VALT_PNT ,0 AS TONGJE_GD FROM RBA_RSK_M X WHERE X.RSK_B_C = 'T' AND X.USYN = 1 AND X.GYLJ_DT IS NOT NULL
AND X.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND X.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND X.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
UNION ALL SELECT 0 AS TRSK_T_CTN ,COUNT(B.RSK_NO) AS TRSK_VALT_CNT ,NVL(SUM(B.KRI_UNTY_RSK_VALT_PNT),0) AS KRI_RSK_VALT_PNT ,NVL(SUM(B.KRI_UNTY_RSK_GD),0) AS KRI_RSK_GD ,NVL(SUM(B.LST_TONGJE_VALT_PNT),0) AS TONGJE_VALT_PNT ,NVL(SUM(B.LST_TONGJE_VALT_GD),0) AS TONGJE_GD FROM RBA_RSK_M A , RBA_TRSK_VALT_I B , VALT_SCHD Z WHERE A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER /* 통합위험 현재회차에서만 구함. */ AND A.LST_VALT_TRN = Z.VALT_TRN AND A.RSK_B_C = 'T' AND A.USYN = '1' AND A.MNG_BRNO = '9999' AND A.GYLJ_DT IS NOT NULL
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
AND B.VALT_JINHG_S_C IN ('2','9') ) DD ) EE ) GG )

SELECT GET_CODE_NAME ('R029', A.RSK_B_C) AS RSK_B_C ,GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_GUBUN ,GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD ,GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.MNG_BRNO) AS JUM_NM , A.DR_DT AS DRDT ,A.RSK_NO ,A.RSK_NM ,A.RSK_CTNT ,A.MNG_BRNO, FN_CDINFO_VAR('DPT', A.MNG_BRNO, '') AS MNG_BRNO_NM ,A.MNGR_JKW_NO, GET_LOGINID_NAME(A.MNGR_JKW_NO) AS MNGR_JKW_NM ,G.RSK_PROC_NM ,G.SUB_PROC_NM ,B.FCST_FRQ_VALT_GD, B.FCST_FRQ_VALT_CTNT --예상빈도평가 ,B.TRSR_LOSS_VALT_GD, B.TRSR_LOSS_VALT_CTNT --재무손실 ,B.INDV_RSK_VALT_PNT, B.INDV_RSK_GD --개인위험평가점수 ,TO_CHAR(TO_DATE(B.EFCT_VALT_DT,'YYYYMMDD'),'YYYY-MM-DD') AS EFCT_VALT_DT --영향평가일자 ,A.LST_VALT_TRN, A.LST_VALT_SER --평가회차/순번 ,A.VALT_JINHG_S_C --평가진행상태 ,(SELECT VALT_TRN FROM RBA_RSK_VALT_SCHD WHERE VALT_G = '1' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN VALT_SDT AND VALT_EDT AND VALT_JUNGJI_YN = '0' AND ROWNUM = 1) AS CUR_VALT_TRN -- 현재평가회차 ,REL_DATA_CTNT FROM RBA_RSK_M A -- 개별위험 LEFT JOIN RBA_IRSK_VALT_I B -- 개별위험평가 ON A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER JOIN RBA_PROC_M G ON A.RSK_PROC_NO = G.RSK_PROC_NO
AND A.RSK_B_C = #{RSK_B_C,jdbcType=VARCHAR}
AND A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
AND A.MNGR_JKW_NO = #{OWNER_ID,jdbcType=VARCHAR}
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
AND B.TONGJE_G_C = #{TONGJE_G_C,jdbcType=VARCHAR}
AND B.TONGJE_FLD_C = #{TONGJE_FLD_C,jdbcType=VARCHAR}
AND B.TONGJE_BUMUN_C = #{TONGJE_BUMUN_C,jdbcType=VARCHAR}
ORDER BY A.RSK_B_C, A.RSK_G_C

SELECT D01, D02, D03, D04, D05, D06, D07, D08, D09, D10, D11, D12 FROM ( SELECT SUM(DECODE(RSK_B_C, 'I', CNT,0)) AS D01 ,SUM(DECODE(RSK_B_C, 'T', CNT,0)) AS D02 ,SUM(DECODE(RSK_B_C, 'I', 1,0)) AS D03 ,SUM(DECODE(RSK_B_C, 'T', 1,0)) AS D04 FROM ( SELECT RSK_B_C, MNG_BRNO, COUNT(*) AS CNT FROM RBA_RSK_M X WHERE USYN = '1'
AND RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
GROUP BY RSK_B_C, MNG_BRNO ) ) AA, (SELECT COUNT(DISTINCT RSK_PROC_NO) AS D05 FROM RBA_RSK_M WHERE USYN = 1
AND RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND RSK_B_C = 'I' ) BB, (SELECT COUNT(DISTINCT TONGJE_NO) AS D06 FROM RBA_RSK_M A, RBA_RSK_TONGJE_MP B WHERE A.USYN = 1
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_B_C = 'I' AND A.RSK_NO = B.RSK_NO) CC, (SELECT COUNT(DISTINCT RSK_PROC_NO) AS D07 FROM RBA_RSK_M WHERE USYN = 1
AND RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND RSK_B_C = 'T') DD, (SELECT COUNT(DISTINCT TONGJE_NO) AS D08 FROM RBA_RSK_M A, RBA_RSK_TONGJE_MP B WHERE A.USYN = 1
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_B_C = 'T' AND A.RSK_NO = B.RSK_NO) EE, (SELECT SUM(DECODE(RSK_B_C, 'I', CNT,0)) AS D09, SUM(DECODE(RSK_B_C, 'T', CNT,0)) AS D10 FROM (SELECT RSK_B_C, COUNT(*) CNT FROM RBA_KRI_M WHERE USYN = '1' GROUP BY RSK_B_C )) FF, (SELECT SUM(DECODE(RSK_B_C, 'I', CNT,0)) AS D11, SUM(DECODE(RSK_B_C, 'T', CNT,0)) AS D12 FROM (SELECT RSK_B_C, COUNT(*) CNT FROM RBA_KCI_M WHERE USYN = '1' GROUP BY RSK_B_C )) GG

SELECT GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_GUBUN ,GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD ,GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.MNG_BRNO) AS JUM_NM , A.DR_DT AS DRDT ,A.RSK_NO ,A.RSK_NM ,A.RSK_CTNT ,A.MNG_BRNO, FN_CDINFO_VAR('DPT', A.MNG_BRNO, '') AS MNG_BRNO_NM ,A.MNGR_JKW_NO, GET_LOGINID_NAME(A.MNGR_JKW_NO) AS MNGR_JKW_NM ,G.RSK_PROC_NM ,G.SUB_PROC_NM ,B.FCST_FRQ_VALT_GD, B.FCST_FRQ_VALT_CTNT --예상빈도평가 ,B.TRSR_LOSS_VALT_GD, B.TRSR_LOSS_VALT_CTNT --재무손실 ,B.INDV_RSK_VALT_PNT, B.INDV_RSK_GD --개인위험평가점수 ,TO_CHAR(TO_DATE(B.EFCT_VALT_DT,'YYYYMMDD'),'YYYY-MM-DD') AS EFCT_VALT_DT --영향평가일자 ,A.LST_VALT_TRN, A.LST_VALT_SER --평가회차/순번 ,A.VALT_JINHG_S_C --평가진행상태 ,(SELECT VALT_TRN FROM RBA_RSK_VALT_SCHD WHERE VALT_G = '1' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN VALT_SDT AND VALT_EDT AND VALT_JUNGJI_YN = '0' AND ROWNUM = 1) AS CUR_VALT_TRN -- 현재평가회차 ,REL_DATA_CTNT FROM RBA_RSK_M A -- 개별위험 LEFT JOIN RBA_IRSK_VALT_I B -- 개별위험평가 ON A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER JOIN RBA_PROC_M G ON A.RSK_PROC_NO = G.RSK_PROC_NO AND A.RSK_B_C = 'I'
AND A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
AND A.MNGR_JKW_NO = #{OWNER_ID,jdbcType=VARCHAR}
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
AND B.TONGJE_G_C = #{TONGJE_G_C,jdbcType=VARCHAR}
AND B.TONGJE_FLD_C = #{TONGJE_FLD_C,jdbcType=VARCHAR}
AND B.TONGJE_BUMUN_C = #{TONGJE_BUMUN_C,jdbcType=VARCHAR}
ORDER BY A.RSK_B_C, A.RSK_G_C

SELECT (SELECT COUNT(*) FROM RBA_RSK_KCI_MP WHERE A.RSK_NO = RSK_NO) AS KCI_CNT ,(SELECT COUNT(*) FROM RBA_RSK_KRI_MP WHERE A.RSK_NO = RSK_NO) AS KRI_CNT ,GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_GUBUN ,GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD ,GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.MNG_BRNO) AS JUM_NM , A.DR_DT AS DRDT ,A.RSK_NO ,A.RSK_NM ,A.RSK_CTNT ,A.MNG_BRNO, FN_CDINFO_VAR('DPT', A.MNG_BRNO, '') AS MNG_BRNO_NM ,A.MNGR_JKW_NO, GET_LOGINID_NAME(A.MNGR_JKW_NO) AS MNGR_JKW_NM ,G.RSK_PROC_NM ,G.SUB_PROC_NM ,B.FCST_FRQ_VALT_GD, B.FCST_FRQ_VALT_CTNT --예상빈도평가 ,B.TRSR_LOSS_VALT_GD, B.TRSR_LOSS_VALT_CTNT --재무손실 ,B.INDV_RSK_VALT_PNT, B.INDV_RSK_GD --개인위험평가점수 ,TO_CHAR(TO_DATE(B.EFCT_VALT_DT,'YYYYMMDD'),'YYYY-MM-DD') AS EFCT_VALT_DT --영향평가일자 ,A.LST_VALT_TRN, A.LST_VALT_SER --평가회차/순번 ,A.VALT_JINHG_S_C --평가진행상태 ,(SELECT VALT_TRN FROM RBA_RSK_VALT_SCHD WHERE VALT_G = '1' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN VALT_SDT AND VALT_EDT AND VALT_JUNGJI_YN = '0' AND ROWNUM = 1) AS CUR_VALT_TRN -- 현재평가회차 ,REL_DATA_CTNT FROM RBA_RSK_M A -- 개별위험 LEFT JOIN RBA_IRSK_VALT_I B -- 개별위험평가 ON A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER JOIN RBA_PROC_M G ON A.RSK_PROC_NO = G.RSK_PROC_NO AND A.RSK_B_C = 'T'
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
ORDER BY A.RSK_B_C, A.RSK_G_C

SELECT C.KRI_UNTY_RSK_GD ,C.KCI_TONGJE_EFCT_GD ,C.REMDR_RSK_GD_SER ,GET_RBA_RSK_NAME('RSK_G', A.RSK_G_C) AS RSK_GUBUN ,GET_RBA_RSK_NAME('RSK_F', A.RSK_FLD_C) AS RSK_FLD ,GET_RBA_RSK_NAME('RSK_B', A.RSK_BUMUN_C) AS RSK_BUMUN ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.MNG_BRNO) AS JUM_NM , A.DR_DT AS DRDT ,A.RSK_NO ,A.RSK_NM ,A.RSK_CTNT ,A.MNG_BRNO, FN_CDINFO_VAR('DPT', A.MNG_BRNO, '') AS MNG_BRNO_NM ,A.MNGR_JKW_NO, GET_LOGINID_NAME(A.MNGR_JKW_NO) AS MNGR_JKW_NM ,G.RSK_PROC_NM ,G.SUB_PROC_NM ,B.FCST_FRQ_VALT_GD, B.FCST_FRQ_VALT_CTNT --예상빈도평가 ,B.TRSR_LOSS_VALT_GD, B.TRSR_LOSS_VALT_CTNT --재무손실 ,B.INDV_RSK_VALT_PNT, B.INDV_RSK_GD --개인위험평가점수 ,TO_CHAR(TO_DATE(B.EFCT_VALT_DT,'YYYYMMDD'),'YYYY-MM-DD') AS EFCT_VALT_DT --영향평가일자 ,A.LST_VALT_TRN, A.LST_VALT_SER --평가회차/순번 ,A.VALT_JINHG_S_C --평가진행상태 ,(SELECT VALT_TRN FROM RBA_RSK_VALT_SCHD WHERE VALT_G = '1' AND TO_CHAR(SYSDATE, 'YYYYMMDD') BETWEEN VALT_SDT AND VALT_EDT AND VALT_JUNGJI_YN = '0' AND ROWNUM = 1) AS CUR_VALT_TRN -- 현재평가회차 ,REL_DATA_CTNT FROM RBA_RSK_M A -- 개별위험 LEFT JOIN RBA_IRSK_VALT_I B -- 개별위험평가 ON A.RSK_NO = B.RSK_NO AND A.LST_VALT_TRN = B.VALT_TRN AND A.LST_VALT_SER = B.VALT_SER JOIN RBA_PROC_M G ON A.RSK_PROC_NO = G.RSK_PROC_NO AND A.RSK_B_C = 'T' JOIN RBA_TRSK_VALT_I C ON A.RSK_NO = C.RSK_NO
AND A.MNG_BRNO = #{MNG_BRNO,jdbcType=VARCHAR}
AND A.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND A.RSK_FLD_C = #{RSK_FLD_C,jdbcType=VARCHAR}
AND A.RSK_BUMUN_C = #{RSK_BUMUN_C,jdbcType=VARCHAR}
ORDER BY A.RSK_B_C, A.RSK_G_C

SELECT DISTINCT KRI.KRI_NO ,M.KRI_NM ,S.KRI_V ,GET_CODE_NAME ('R011', M.UNIT_C) AS UNIT_NM ,S.VALT_PNT ,S.VALT_GD ,S.KRI_GJDT ,M.KRI_CTNT FROM RBA_RSK_M X ,RBA_RSK_KRI_MP KRI ,RBA_KRI_M M ,RBA_TKRI_S S WHERE X.RSK_B_C = 'T' AND X.USYN = 1
AND X.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND X.GYLJ_DT IS NOT NULL AND X.RSK_NO = KRI.RSK_NO AND KRI.KRI_NO = M.KRI_NO AND KRI.KRI_NO = S.KRI_NO AND S.MNG_BRNO = '9999'

SELECT DISTINCT KCI.KCI_NO ,M.KCI_NM ,S.KCI_V ,GET_CODE_NAME ('R026', M.UNIT_C) AS UNIT_NM ,S.VALT_PNT ,S.VALT_GD ,S.KCI_GJDT ,M.KCI_CTNT FROM RBA_RSK_M X ,RBA_RSK_KCI_MP KCI ,RBA_KCI_M M ,RBA_TKCI_S S WHERE X.RSK_B_C = 'T' AND X.USYN = 1
AND X.RSK_G_C = #{RSK_G_C,jdbcType=VARCHAR}
AND X.GYLJ_DT IS NOT NULL AND X.RSK_NO = KCI.RSK_NO AND KCI.KCI_NO = M.KCI_NO AND KCI.KCI_NO = S.KCI_NO AND S.MNG_BRNO = '9999'
